package Session;

use strict;
use warnings;
use Storable qw(nstore retrieve lock_nstore lock_retrieve);
use Digest::SHA qw(sha256_hex);
use File::Spec;

sub new {
    my ($class, %opts) = @_;

    my $self = bless {
        session_dir     => $opts{session_dir}     || $SESSION_DIR,
        session_prefix  => $opts{session_prefix}  || $SESSION_PREFIX,
        session_timeout => $opts{session_timeout} || $SESSION_TIMEOUT,
        cookie_name     => $opts{cookie_name}     || $COOKIE_NAME,
        session_id      => undef,
        data            => {},
        is_new          => 0,
        modified        => 0,
    }, $class;

    return $self;
}

# Generate a cryptographically random session ID
sub _generate_session_id {
    my ($self) = @_;
    my $random_data = join('', map { chr(int(rand(256))) } 1..32);
    my $session_id = sha256_hex($random_data . time() . $$ . rand());
    return $session_id;
}

# Validate session ID format to prevent directory traversal
sub _validate_session_id {
    my ($self, $session_id) = @_;

    # Only allow hex characters (output of sha256_hex)
    if (defined $session_id && $session_id =~ /\A[a-f0-9]{64}\z/) {
        return 1;
    }
    return 0;
}

# Get the full file path for a session
sub _session_file {
    my ($self, $session_id) = @_;
    $session_id ||= $self->{session_id};
    return File::Spec->catfile(
        $self->{session_dir},
        $self->{session_prefix} . $session_id
    );
}

# Load or create a session based on cookie
sub load_or_create {
    my ($self, $cgi) = @_;

    $cgi ||= CGI->new();

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    my $session_id;

    if (exists $cookies{$self->{cookie_name}}) {
        $session_id = $cookies{$self->{cookie_name}}->value();
    }

    # Attempt to load existing session
    if ($self->_validate_session_id($session_id)) {
        my $loaded = $self->load($session_id);
        if ($loaded) {
            # Check if session has expired
            if ($self->_is_expired()) {
                $self->destroy();
                return $self->_create_new_session();
            }
            # Update last access time
            $self->{data}{_last_access} = time();
            $self->{modified} = 1;
            return 1;
        }
    }

    # Create new session if loading failed
    return $self->_create_new_session();
}

# Create a brand new session
sub _create_new_session {
    my ($self) = @_;

    $self->{session_id} = $self->_generate_session_id();
    $self->{data} = {
        _created     => time(),
        _last_access => time(),
    };
    $self->{is_new}   = 1;
    $self->{modified} = 1;

    return 1;
}

# Load session data from file using retrieve()
sub load {
    my ($self, $session_id) = @_;

    return 0 unless $self->_validate_session_id($session_id);

    my $session_file = $self->_session_file($session_id);

    unless (-e $session_file && -r $session_file) {
        warn "Session file not found: $session_file\n";
        return 0;
    }

    eval {
        $self->{data} = lock_retrieve($session_file);
    };

    if ($@ || !defined $self->{data} || ref($self->{data}) ne 'HASH') {
        warn "Failed to retrieve session data from $session_file: $@\n";
        $self->{data} = {};
        return 0;
    }

    $self->{session_id} = $session_id;
    $self->{is_new}     = 0;

    return 1;
}

# Save session data to file using nstore()
sub save {
    my ($self) = @_;

    unless ($self->{session_id}) {
        warn "No session ID set; cannot save session.\n";
        return 0;
    }

    my $session_file = $self->_session_file();

    # Ensure session directory exists
    unless (-d $self->{session_dir}) {
        mkdir $self->{session_dir}, 0700
            or die "Cannot create session directory $self->{session_dir}: $!\n";
    }

    eval {
        lock_nstore($self->{data}, $session_file);
    };

    if ($@) {
        warn "Failed to store session data to $session_file: $@\n";
        return 0;
    }

    # Set restrictive permissions
    chmod 0600, $session_file;

    $self->{modified} = 0;
    return 1;
}

# Get a session value
sub get {
    my ($self, $key) = @_;
    return $self->{data}{$key};
}

# Set a session value
sub set {
    my ($self, $key, $value) = @_;
    $self->{data}{$key} = $value;
    $self->{modified} = 1;
    return 1;
}

# Delete a session value
sub delete {
    my ($self, $key) = @_;
    if (exists $self->{data}{$key}) {
        delete $self->{data}{$key};
        $self->{modified} = 1;
        return 1;
    }
    return 0;
}

# Get all session keys (excluding internal ones)
sub keys {
    my ($self) = @_;
    return grep { !/\A_/ } keys %{$self->{data}};
}

# Get the session ID
sub session_id {
    my ($self) = @_;
    return $self->{session_id};
}

# Check if this is a new session
sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

# Check if session has expired
sub _is_expired {
    my ($self) = @_;
    my $last_access = $self->{data}{_last_access} || 0;
    return (time() - $last_access) > $self->{session_timeout};
}

# Destroy the session (remove file and clear data)
sub destroy {
    my ($self) = @_;

    if ($self->{session_id}) {
        my $session_file = $self->_session_file();
        if (-e $session_file) {
            unlink $session_file
                or warn "Failed to remove session file $session_file: $!\n";
        }
    }

    $self->{data}       = {};
    $self->{session_id} = undef;
    $self->{is_new}     = 0;
    $self->{modified}   = 0;

    return 1;
}

# Generate a CGI::Cookie object for the session
sub cookie {
    my ($self, %opts) = @_;

    my $cookie = CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id} || '',
        -expires  => $opts{expires}  || '+1h',
        -path     => $opts{path}     || '/',
        -secure   => $opts{secure}   // 1,
        -httponly  => $opts{httponly} // 1,
        -samesite => $opts{samesite} || 'Strict',
    );

    return $cookie;
}

# Generate an expired cookie (for logout)
sub expire_cookie {
    my ($self, %opts) = @_;

    my $cookie = CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => '',
        -expires  => '-1d',
        -path     => $opts{path} || '/',
        -secure   => $opts{secure}   // 1,
        -httponly  => $opts{httponly} // 1,
    );

    return $cookie;
}

# Cleanup expired sessions from the session directory
sub cleanup_expired {
    my ($self) = @_;

    my $dir = $self->{session_dir};
    my $prefix = $self->{session_prefix};
    my $count = 0;

    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory $dir: $!\n";
        return 0;
    };

    while (my $file = readdir($dh)) {
        next unless $file =~ /\A\Q$prefix\E([a-f0-9]{64})\z/;

        my $filepath = File::Spec->catfile($dir, $file);

        eval {
            my $data = retrieve($filepath);
            if (ref($data) eq 'HASH') {
                my $last_access = $data->{_last_access} || 0;
                if ((time() - $last_access) > $self->{session_timeout}) {
                    unlink $filepath;
                    $count++;
                }
            }
        };

        if ($@) {
            # Corrupted session file; remove it
            unlink $filepath;
            $count++;
        }
    }

    closedir($dh);
    return $count;
}

